const message = $input.item.json.message.toLowerCase();

// Simple regex-based intent parser
// In production, replace with an AI/NLP call for better accuracy
const checkinMatch = message.match(/(check.?in|masuk|tiba|arrive)[:\s]*(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4}|\d{4}-\d{2}-\d{2})/i);
const checkoutMatch = message.match(/(check.?out|keluar|pulang|depart)[:\s]*(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4}|\d{4}-\d{2}-\d{2})/i);
const guestMatch = message.match(/(\d+)\s*(orang|tamu|guest|pax|person)/i);

return [{
  json: {
    phone: $input.item.json.phone,
    message: $input.item.json.message,
    timestamp: $input.item.json.timestamp,
    checkin: checkinMatch ? checkinMatch[2] : null,
    checkout: checkoutMatch ? checkoutMatch[2] : null,
    guestCount: guestMatch ? parseInt(guestMatch[1]) : null,
    hasMissingInfo: !checkinMatch || !checkoutMatch || !guestMatch
  }
}];

const checkin = new Date($input.item.json.checkin);
const checkout = new Date($input.item.json.checkout);
const nights = Math.ceil((checkout - checkin) / (1000 * 60 * 60 * 24));
const guestCount = $input.item.json.guestCount || 2;
const isAvailable = $input.item.json.available !== false; // from availability response

// --- Pricing Logic ---
// Adjust base rate and seasonal multipliers as needed
const BASE_RATE_PER_NIGHT = 1500000; // IDR 1.5jt per malam
const HIGH_SEASON_MONTHS = [7, 8, 12, 1]; // July, Aug, Dec, Jan
const month = checkin.getMonth() + 1;
const isHighSeason = HIGH_SEASON_MONTHS.includes(month);
const seasonMultiplier = isHighSeason ? 1.3 : 1.0;

const totalPrice = nights * BASE_RATE_PER_NIGHT * seasonMultiplier;
const formattedPrice = new Intl.NumberFormat('id-ID', {
  style: 'currency', currency: 'IDR', maximumFractionDigits: 0
}).format(totalPrice);

return [{
  json: {
    ...$input.item.json,
    nights,
    isAvailable,
    isHighSeason,
    totalPrice,
    formattedPrice,
    quotationMessage: isAvailable
      ? `Halo! Berikut penawaran kami 🏡\n\n📅 Check-in: ${$input.item.json.checkin}\n📅 Check-out: ${$input.item.json.checkout}\n👥 Tamu: ${guestCount} orang\n🌙 Durasi: ${nights} malam\n\n💰 Total: ${formattedPrice}\n${isHighSeason ? '(High season rate)' : ''}\n\nHarga sudah termasuk sarapan & welcome drink. ✅\n\nApakah Anda ingin melanjutkan booking? Balas "YA" untuk konfirmasi! 😊`
      : `Maaf, untuk tanggal ${$input.item.json.checkin} – ${$input.item.json.checkout} villa kami sudah penuh. 😔\n\nApakah Anda fleksibel dengan tanggal lain? Kami dengan senang hati bantu carikan alternatif! 🗓️`
  }
}];
